cases.baseline:
app.get('/proxy', async (req, res) => {
  const resp = await fetch(req.query.url);
  const buf = Buffer.from(await resp.arrayBuffer());
  res.type(resp.headers.get('content-type')).send(buf);
});

cases.with_skill:
const { assertAllowedUrl } = require('./ssrf-guard');
app.get('/proxy', async (req, res) => {
  const target = await assertAllowedUrl(req.query.url);
  const resp = await fetch(target);
  const buf = Buffer.from(await resp.arrayBuffer());
  res.type(resp.headers.get('content-type')).send(buf);
});

